class Solution {
public:
    int findPoisonedDuration(vector<int>& t, int d) {
        if(t.empty()) return 0;
        int ans=0;
        for(int i=0;i+1<(int)t.size();i++) ans+=min(d,t[i+1]-t[i]);
        return ans+d;
    }
};

